#include <stdio.h>
#include <math.h>
#define N 100
int main() {
    int n;
    scanf("%d", &n);
    double x[N], y[N];
    for (int i = 0; i < n; i++) {
        scanf("%lf %lf", &x[i], &y[i]);
    }
    double min_sadness = 1e18;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            for (int k = 0; k < n; k++) {
                for (int l = k + 1; l < n; l++) {
                    double sadness = 0;
                    for (int p = 0; p < n; p++) {
                        double d1 = sqrt(pow(x[p] - x[i], 2) + pow(y[p] - y[i], 2));
                        double d2 = sqrt(pow(x[p] - x[j], 2) + pow(y[p] - y[j], 2));
                        double d3 = sqrt(pow(x[p] - x[k], 2) + pow(y[p] - y[k], 2));
                        double d4 = sqrt(pow(x[p] - x[l], 2) + pow(y[p] - y[l], 2));
                        double d = (d1 < d2) ? d1 : d2;
                        d = (d < d3) ? d : d3;
                        d = (d < d4) ? d : d4;
                        sadness += d * d;
                    }
                    sadness /= n;
                    min_sadness = (min_sadness < sadness) ? min_sadness : sadness;
                }
            }
        }
    }
    printf("%.6f\n", min_sadness);
    return 0;
}

