        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = 0; k < n; k++) {
                    for (int l = k + 1; l < n; l++) {
                        double sadness = 0;
                        for (int p = 0; p < n; p++) {
                            double d1 = Math.sqrt(Math.pow(x[p] - x[i], 2) + Math.pow(y[p] - y[i], 2));
                            double d2 = Math.sqrt(Math.pow(x[p] - x[j], 2) + Math.pow(y[p] - y[j], 2));
                            double d3 = Math.sqrt(Math.pow(x[p] - x[k], 2) + Math.pow(y[p] - y[k], 2));
                            double d4 = Math.sqrt(Math.pow(x[p] - x[l], 2) + Math.pow(y[p] - y[l], 2));
                            double d = Math.min(Math.min(d1, d2), Math.min(d3, d4));
